export type ParsedClaimInstruction<
  TProgram extends string = typeof ASYNC_VAULT_PROGRAM_ADDRESS,
  TAccountMetas extends readonly AccountMeta[] = readonly AccountMeta[],
> = {
  programAddress: Address<TProgram>;
  accounts: {
    user: TAccountMetas[0];
    /** Necessary to send Request owner rent if Operator is claiming. */
    owner: TAccountMetas[1];
    assetMint: TAccountMetas[2];
    shareMint: TAccountMetas[3];
    vault: TAccountMetas[4];
    request: TAccountMetas[5];
    /** Pending deposit vault — source for Redeem claims */
    pendingVault?: TAccountMetas[6] | undefined;
    /**
     * User's share TokenAccount — receives minted shares on Deposit (must be owned by
     * request.owner)
     */
    userShareAccount?: TAccountMetas[7] | undefined;
    /**
     * User's asset TokenAccount — receives transferred assets on Redeem (must be owned by
     * request.owner)
     */
    userAssetAccount?: TAccountMetas[8] | undefined;
    assetTokenProgram: TAccountMetas[9];
    /** Token program for share mint operations — only required for Deposit */
    shareTokenProgram?: TAccountMetas[10] | undefined;
  };
  data: ClaimInstructionData;
};

export function parseClaimInstruction<
  TProgram extends string,
  TAccountMetas extends readonly AccountMeta[],
>(
  instruction: Instruction<TProgram> &
    InstructionWithAccounts<TAccountMetas> &
    InstructionWithData<ReadonlyUint8Array>,
): ParsedClaimInstruction<TProgram, TAccountMetas> {
  if (instruction.accounts.length < 11) {
    // TODO: Coded error.
    throw new Error("Not enough accounts");
  }
  let accountIndex = 0;
  const getNextAccount = () => {
    const accountMeta = (instruction.accounts as TAccountMetas)[accountIndex]!;
    accountIndex += 1;
    return accountMeta;
  };
  const getNextOptionalAccount = () => {
    const accountMeta = getNextAccount();
    return accountMeta.address === ASYNC_VAULT_PROGRAM_ADDRESS
      ? undefined
      : accountMeta;
  };
  return {
    programAddress: instruction.programAddress,
    accounts: {
      user: getNextAccount(),
      owner: getNextAccount(),
      assetMint: getNextAccount(),
      shareMint: getNextAccount(),
      vault: getNextAccount(),
      request: getNextAccount(),
      pendingVault: getNextOptionalAccount(),
      userShareAccount: getNextOptionalAccount(),
      userAssetAccount: getNextOptionalAccount(),
      assetTokenProgram: getNextAccount(),
      shareTokenProgram: getNextOptionalAccount(),
    },
    data: getClaimInstructionDataDecoder().decode(instruction.data),
  };
}
